function parseRange(s) {
    const hyphenIndex = s.indexOf('-');

    if (hyphenIndex === -1) {
        return [parseInt(s, 10)];
    }

    const lastHyphenIndex = s.lastIndexOf('-');

    if (lastHyphenIndex === 0) {
        return [parseInt(s, 10)];
    }

    const a = parseInt(s.substring(0, lastHyphenIndex), 10);
    const b = parseInt(s.substring(lastHyphenIndex + 1), 10);

    if (a <= b) {
        const result = [];
        for (let i = a; i <= b; i++) result.push(i);
        return result;
    } else {
        const result = [];
        for (let i = a; i >= b; i--) result.push(i);
        return result;
    }
}
